#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: AWS Instance Profile (Metadata Service)
 *
 * Description: Use AWS instance profile for applications running on EC2.
 * No credentials needed!
 *
 * Prerequisites:
 * - Application running on AWS EC2 instance
 * - EC2 instance has an IAM instance profile attached
 * - IAM role has permissions to access Databricks
 *
 * Setup:
 * 1. Create IAM role with permissions to Databricks
 * 2. Attach role to EC2 instance as instance profile
 * 3. Deploy application to EC2
 *
 * Run (on EC2 instance):
 * ```bash
 * DATABRICKS_HOST="https://your-workspace.cloud.databricks.com" \
 * npx ts-node examples/auth/aws-instance-profile.ts
 * ```
 *
 * Note: The SDK automatically detects and uses EC2 instance metadata service
 */

import {Config, WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const config = new Config({
        host: process.env.DATABRICKS_HOST,
        // SDK automatically detects AWS instance profile
    });

    const client = new WorkspaceClient(config);

    try {
        const user = await client.currentUser.me();
        console.log(
            `✓ Successfully authenticated via AWS instance profile as: ${user.userName}`
        );
        console.log(`  User ID: ${user.id}`);

        console.log(`  Host: ${config.host}`);
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error("\nMake sure:");
        console.error("  1. This code is running on an AWS EC2 instance");
        console.error("  2. EC2 instance has an IAM instance profile attached");
        console.error("  3. IAM role has permissions to Databricks");
        console.error("  4. DATABRICKS_HOST environment variable is set");
        process.exit(1);
    }
}

main().catch(console.error);
